        class Sound
        {
            public void GreetingVoice()
            {
                try
                {
                    SoundPlayer player = new SoundPlayer("Recording_2 - Copy.wav");
                    player.Load();
                    player.PlaySync();
                }
                catch (Exception ex)
                {

                    Console.WriteLine("Error:" + ex.Message);
                }

            }



        }

        public string Bot(string message)
        {
            message = message.ToLower();
            if (message.Contains("how are you"))
                return "I am fine";
            else if (message.Contains("what is your purpose"))
                return "cybersecurity awareness";
            else if (message.Contains("what can i ask about u"))
                return "Password safely, phishing , safe browsing.";
            else if (message.Contains("password safely"))
                return "define what is password safely";
            else return "Sorry, I do not undersand, ask about password safely,phishing,etc";


        }
